#include <bits/stdc++.h>
#define MAXN 200000
using namespace std;
struct node {
	int nxt, to, val;
} e[MAXN << 1];
int n, m;
int tot;
int vis[MAXN];
int head[MAXN];
int r[MAXN];
double dp[MAXN];
void add (int x, int y, int c) {
	e[++tot].nxt = head[x];
	e[tot].to = y;
	e[tot].val = c;
	head[x] = tot;
	return ; 
}
void dfs(int x){
	if (x == n) {
		dp[x] = 0;
		return;
	}
	if (vis[x]) {
		return;
	}
	vis[x] = 1;
	for (int i = head[x]; i; i = e[i].nxt) {
		int v = e[i].to;
		dfs (v);
		dp[x] += (dp[v] + e[i].val) / r[x] * 1.0;
	}
	return ;
}
int main () {
	cin >> n >> m;
	for (int i = 1; i <= m; i++) {
		int a,b,c;
		cin >> a >> b >> c;
		add (a, b, c);
		r[a]++;
	}
	dfs (1);
	cout << fixed << setprecision (2) << dp[1]; 
	return 0;
}
